#include<bits/stdc++.h>
using namespace std;
char s[55];
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>s;
	int l=strlen(s);
	for(int i=0; i<l; ++i)
		if(isupper(s[i])) {
			s[i]=tolower(s[i]);
		} else if(islower(s[i])) {
			s[i]=toupper(s[i]);
		}
	reverse(s,s+l);
	for(int i=0; i<l; ++i) {
		if(s[i]=='x') {
			cout<<'a';
		} else if(s[i]=='X') {
			cout<<'A';
		} else if(s[i]=='y') {
			cout<<'b';
		} else if(s[i]=='Y') {
			cout<<'B';
		} else if(s[i]=='z') {
			cout<<'c';
		} else if(s[i]=='Z') {
			cout<<'C';
		} else {
			cout<<char(s[i]+3);
		}
	}
	return 0;
}
